export interface ParseOptions {
  delimiter?: string;
  quoteChar?: string;
  lineSeparator?: string;
}

export interface ParseError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Record<string, any>[];
  headers: string[];
  errors: ParseError[];
  filter(predicate: (row: Record<string, any>, index: number) => boolean): Record<string, any>[];
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<string | number | null, Record<string, any>[]>;
}

function coerceType(value: string): any {
  // Handle null cases
  if (value === '' || value === 'null' || value === 'NULL') {
    return null;
  }

  // Handle booleans (case insensitive)
  if (value.toLowerCase() === 'true') {
    return true;
  }
  if (value.toLowerCase() === 'false') {
    return false;
  }

  // Handle numbers (int and float)
  if (/^-?\d+$/.test(value)) {
    return parseInt(value, 10);
  }
  if (/^-?\d*\.\d+$/.test(value)) {
    return parseFloat(value);
  }

  // Everything else is a string
  return value;
}

function parseCSVContent(
  input: string,
  delimiter: string = ',',
  quoteChar: string = '"',
  lineSeparator: string = '\n'
): { rows: string[][]; errors: ParseError[] } {
  const errors: ParseError[] = [];
  const rows: string[][] = [];

  // Split by line separator
  const lines = input.split(lineSeparator);

  let currentRow: string[] = [];
  let currentField = '';
  let insideQuotes = false;
  let lineNumber = 0;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];

    for (let j = 0; j < line.length; j++) {
      const char = line[j];
      const nextChar = j + 1 < line.length ? line[j + 1] : null;

      if (char === quoteChar) {
        if (nextChar === quoteChar) {
          // Escaped quote - add one quote and skip next
          currentField += quoteChar;
          j++;
        } else {
          // Toggle quote state
          insideQuotes = !insideQuotes;
        }
      } else if (char === delimiter && !insideQuotes) {
        // Field separator
        currentRow.push(currentField);
        currentField = '';
      } else {
        currentField += char;
      }
    }

    // Handle end of line
    if (insideQuotes && i < lines.length - 1) {
      // Still inside quotes, add the line separator back
      currentField += lineSeparator;
    } else {
      // End of row
      if (currentField || currentRow.length > 0) {
        currentRow.push(currentField);
      }

      if (currentRow.length > 0) {
        // Check for unclosed quotes
        if (insideQuotes) {
          errors.push({
            row: lineNumber,
            message: 'Unclosed quote in row'
          });
        }
        rows.push(currentRow);
        currentRow = [];
        currentField = '';
      }

      lineNumber++;
    }
  }

  // Handle any remaining field/row at end of input
  if (currentField || currentRow.length > 0) {
    if (insideQuotes) {
      errors.push({
        row: lineNumber,
        message: 'Unclosed quote at end of input'
      });
    }
    currentRow.push(currentField);
    if (currentRow.length > 0) {
      rows.push(currentRow);
    }
  }

  return { rows, errors };
}

export function parseCSV(input: string, options: ParseOptions = {}): CSVResult {
  const delimiter = options.delimiter ?? ',';
  const quoteChar = options.quoteChar ?? '"';
  const lineSeparator = options.lineSeparator ?? '\n';

  if (!input || input.trim() === '') {
    return {
      rows: [],
      headers: [],
      errors: [],
      filter: () => [],
      sum: () => 0,
      average: () => 0,
      count: () => 0,
      groupBy: () => new Map()
    };
  }

  const { rows: rawRows, errors: parseErrors } = parseCSVContent(
    input,
    delimiter,
    quoteChar,
    lineSeparator
  );

  if (rawRows.length === 0) {
    return {
      rows: [],
      headers: [],
      errors: parseErrors,
      filter: () => [],
      sum: () => 0,
      average: () => 0,
      count: () => 0,
      groupBy: () => new Map()
    };
  }

  const headers = rawRows[0];
  const rows: Record<string, any>[] = [];
  const errors: ParseError[] = [...parseErrors];

  // Parse data rows
  for (let i = 1; i < rawRows.length; i++) {
    const rawRow = rawRows[i];

    // Check if row has correct number of fields
    if (rawRow.length !== headers.length) {
      errors.push({
        row: i,
        message: `Expected ${headers.length} fields, got ${rawRow.length}`
      });
    }

    const row: Record<string, any> = {};
    for (let j = 0; j < headers.length; j++) {
      const header = headers[j];
      const value = rawRow[j] ?? '';
      row[header] = coerceType(value);
    }
    rows.push(row);
  }

  // Helper methods
  const filter = (predicate: (row: Record<string, any>, index: number) => boolean): Record<string, any>[] => {
    return rows.filter(predicate);
  };

  const sum = (column: string): number => {
    return rows.reduce((acc, row) => {
      const value = row[column];
      if (typeof value === 'number') {
        return acc + value;
      }
      return acc;
    }, 0);
  };

  const average = (column: string): number => {
    const numericRows = rows.filter(row => typeof row[column] === 'number');
    if (numericRows.length === 0) return 0;
    return sum(column) / numericRows.length;
  };

  const count = (): number => {
    return rows.length;
  };

  const groupBy = (column: string): Map<string | number | null, Record<string, any>[]> => {
    const map = new Map<string | number | null, Record<string, any>[]>();
    for (const row of rows) {
      const key = row[column];
      if (!map.has(key)) {
        map.set(key, []);
      }
      map.get(key)!.push(row);
    }
    return map;
  };

  return {
    rows,
    headers,
    errors,
    filter,
    sum,
    average,
    count,
    groupBy
  };
}

import { parseCSV } from './csv-parser';

function assert(condition: boolean, message: string) {
  if (!condition) {
    throw new Error(`Assertion failed: ${message}`);
  }
}

function assertEquals<T>(actual: T, expected: T, message: string) {
  if (JSON.stringify(actual) !== JSON.stringify(expected)) {
    throw new Error(`Assertion failed: ${message}\nExpected: ${JSON.stringify(expected)}\nActual: ${JSON.stringify(actual)}`);
  }
}

function testBasicParsing() {
  console.log('Testing: Basic Parsing');
  const csv = `name,age,city
John,25,New York
Jane,30,Los Angeles
Bob,35,Chicago`;

  const result = parseCSV(csv);

  assertEquals(result.headers, ['name', 'age', 'city'], 'Headers should be correct');
  assertEquals(result.count(), 3, 'Should have 3 rows');
  assertEquals(result.rows[0].name, 'John', 'First row name should be John');
  assertEquals(result.rows[0].age, 25, 'First row age should be 25 (coerced to number)');
  assertEquals(result.errors.length, 0, 'Should have no parsing errors');
  console.log('✓ Basic parsing test passed');
}

function testQuotedFields() {
  console.log('Testing: Quoted Fields with Commas');
  const csv = `name,description,price
"John Doe","A person, very nice",100
"Jane Smith","Another person, also nice",200`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0].name, 'John Doe', 'Quoted name should work');
  assertEquals(result.rows[0].description, 'A person, very nice', 'Quoted field with comma should work');
  assertEquals(result.rows[0].price, 100, 'Price should be coerced to number');
  assertEquals(result.errors.length, 0, 'Should have no parsing errors');
  console.log('✓ Quoted fields test passed');
}

function testEscapedQuotes() {
  console.log('Testing: Escaped Quotes');
  const csv = `name,comment
"John ""The Man"" Doe","He said ""Hello"""
"Jane ""The Woman"" Smith","She replied ""Hi"""`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0].name, 'John "The Man" Doe', 'Double quotes should be escaped');
  assertEquals(result.rows[0].comment, 'He said "Hello"', 'Escaped quotes in value should work');
  assertEquals(result.rows[1].name, 'Jane "The Woman" Smith', 'Another escaped quote test');
  assertEquals(result.errors.length, 0, 'Should have no parsing errors');
  console.log('✓ Escaped quotes test passed');
}

function testCustomDelimiters() {
  console.log('Testing: Custom Delimiters');
  const csv = `name;age;city
John;25;New York
Jane;30;Los Angeles`;

  const result = parseCSV(csv, { delimiter: ';' });

  assertEquals(result.headers, ['name', 'age', 'city'], 'Should parse with semicolon delimiter');
  assertEquals(result.rows[0].name, 'John', 'First field should be correct');
  assertEquals(result.rows[0].age, 25, 'Second field should be correct');
  assertEquals(result.errors.length, 0, 'Should have no parsing errors');
  console.log('✓ Custom delimiters test passed');
}

function testCustomQuoteChar() {
  console.log('Testing: Custom Quote Character');
  const csv = `name,description,price
'John Doe','A person, very nice',100
'Jane Smith','Another person, also nice',200`;

  const result = parseCSV(csv, { quoteChar: "'" });

  assertEquals(result.rows[0].name, 'John Doe', 'Single quote should work as quote char');
  assertEquals(result.rows[0].description, 'A person, very nice', 'Field with comma should work with single quotes');
  assertEquals(result.errors.length, 0, 'Should have no parsing errors');
  console.log('✓ Custom quote character test passed');
}

function testCustomLineSeparator() {
  console.log('Testing: Custom Line Separator');
  const csv = `name,age,city\rJohn,25,New York\rJane,30,Los Angeles`;

  const result = parseCSV(csv, { lineSeparator: '\r' });

  assertEquals(result.headers, ['name', 'age', 'city'], 'Should parse with custom line separator');
  assertEquals(result.count(), 2, 'Should have 2 rows');
  assertEquals(result.errors.length, 0, 'Should have no parsing errors');
  console.log('✓ Custom line separator test passed');
}

function testTypeCoercionNumbers() {
  console.log('Testing: Type Coercion - Numbers');
  const csv = `name,intValue,floatValue
John,42,3.14
Jane,100,2.71828`;

  const result = parseCSV(csv);

  assertEquals(typeof result.rows[0].intValue, 'number', 'Integer should be coerced to number');
  assertEquals(result.rows[0].intValue, 42, 'Integer value should be correct');
  assertEquals(typeof result.rows[0].floatValue, 'number', 'Float should be coerced to number');
  assertEquals(result.rows[0].floatValue, 3.14, 'Float value should be correct');
  assertEquals(result.rows[1].intValue, 100, 'Another integer should work');
  console.log('✓ Type coercion - numbers test passed');
}

function testTypeCoercionBooleans() {
  console.log('Testing: Type Coercion - Booleans');
  const csv = `name,isActive,isVip
John,true,False
Jane,TRUE,FALSE
Bob,false,true`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0].isActive, true, 'true should be coerced to boolean');
  assertEquals(result.rows[0].isVip, false, 'False should be coerced to boolean (case insensitive)');
  assertEquals(result.rows[1].isActive, true, 'TRUE should be coerced to boolean');
  assertEquals(result.rows[2].isActive, false, 'false should be coerced to boolean');
  console.log('✓ Type coercion - booleans test passed');
}

function testTypeCoercionNulls() {
  console.log('Testing: Type Coercion - Nulls');
  const csv = `name,nullValue,NULLValue,emptyValue
John,null,NULL,
Jane,NULL,null,`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0].nullValue, null, 'null should be coerced to null');
  assertEquals(result.rows[0].NULLValue, null, 'NULL should be coerced to null');
  assertEquals(result.rows[0].emptyValue, null, 'Empty string should be coerced to null');
  assertEquals(result.rows[1].nullValue, null, 'NULL should be coerced to null');
  console.log('✓ Type coercion - nulls test passed');
}

function testTypeCoercionStrings() {
  console.log('Testing: Type Coercion - Strings');
  const csv = `name,value
John,hello
Jane,world123
Bob,3.14x`;

  const result = parseCSV(csv);

  assertEquals(typeof result.rows[0].value, 'string', 'Non-numeric value should stay string');
  assertEquals(result.rows[0].value, 'hello', 'String value should be correct');
  assertEquals(result.rows[1].value, 'world123', 'Mixed alphanumeric should stay string');
  assertEquals(result.rows[2].value, '3.14x', 'Invalid number should stay string');
  console.log('✓ Type coercion - strings test passed');
}

function testNegativeNumbers() {
  console.log('Testing: Negative Numbers');
  const csv = `name,intValue,floatValue
John,-42,-3.14
Jane,-100,-2.71828`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0].intValue, -42, 'Negative integer should work');
  assertEquals(result.rows[0].floatValue, -3.14, 'Negative float should work');
  console.log('✓ Negative numbers test passed');
}

function testMalformedRows() {
  console.log('Testing: Malformed Row Error Collection');
  const csv = `name,age,city
John,25,New York
Jane,30
Bob,35,Chicago,Extra`;

  const result = parseCSV(csv);

  assertEquals(result.count(), 3, 'Should still parse all rows despite errors');
  assertEquals(result.errors.length, 2, 'Should have 2 errors for malformed rows');
  assert(result.errors[0].row === 2, 'First error should be on row 2');
  assert(result.errors[1].row === 4, 'Second error should be on row 4');
  assert(result.errors[0].message.includes('Expected 3 fields'), 'Error message should indicate field mismatch');
  console.log('✓ Malformed rows test passed');
}

function testFilterFunctionality() {
  console.log('Testing: Filter Functionality');
  const csv = `name,age,city
John,25,New York
Jane,30,Los Angeles
Bob,35,Chicago
Alice,22,New York`;

  const result = parseCSV(csv);

  const filtered = result.filter((row) => row.age > 25);
  assertEquals(filtered.length, 3, 'Filter should return 3 rows with age > 25');
  assert(filtered.every(row => row.age > 25), 'All filtered rows should have age > 25');

  const byCity = result.filter((row) => row.city === 'New York');
  assertEquals(byCity.length, 2, 'Filter should return 2 rows from New York');
  console.log('✓ Filter functionality test passed');
}

function testSumAggregation() {
  console.log('Testing: Sum Aggregation');
  const csv = `name,salary
John,50000
Jane,60000
Bob,55000
Alice,65000`;

  const result = parseCSV(csv);

  const total = result.sum('salary');
  assertEquals(total, 230000, 'Sum should be correct');

  const filtered = result.filter((row) => row.name !== 'Alice');
  // Note: filter returns array, not CSVResult, so we need to manually sum
  const filterSum = filtered.reduce((sum, row) => sum + row.salary, 0);
  assertEquals(filterSum, 165000, 'Sum on filtered rows should be correct');
  console.log('✓ Sum aggregation test passed');
}

function testAverageAggregation() {
  console.log('Testing: Average Aggregation');
  const csv = `name,score
John,85
Jane,90
Bob,75
Alice,95`;

  const result = parseCSV(csv);

  const avg = result.average('score');
  assertEquals(avg, 86.25, 'Average should be correct');
  console.log('✓ Average aggregation test passed');
}

function testAverageWithNulls() {
  console.log('Testing: Average with Null Values');
  const csv = `name,score
John,85
Jane,null
Bob,75
Alice,95`;

  const result = parseCSV(csv);

  const avg = result.average('score');
  assertEquals(avg, 85, 'Average should ignore null values and calculate from 3 numbers');
  console.log('✓ Average with nulls test passed');
}

function testCountAggregation() {
  console.log('Testing: Count Aggregation');
  const csv = `name,age
John,25
Jane,30
Bob,35`;

  const result = parseCSV(csv);

  const count = result.count();
  assertEquals(count, 3, 'Count should return 3');
  console.log('✓ Count aggregation test passed');
}

function testGroupByAggregation() {
  console.log('Testing: GroupBy Aggregation');
  const csv = `name,department,salary
John,Sales,50000
Jane,Engineering,60000
Bob,Sales,55000
Alice,Engineering,65000`;

  const result = parseCSV(csv);

  const grouped = result.groupBy('department');
  assertEquals(grouped.size, 2, 'Should have 2 groups');
  assertEquals(grouped.get('Sales')?.length, 2, 'Sales group should have 2 rows');
  assertEquals(grouped.get('Engineering')?.length, 2, 'Engineering group should have 2 rows');

  const salesGroup = grouped.get('Sales');
  assert(salesGroup?.every(row => row.department === 'Sales'), 'All rows in group should have matching value');
  console.log('✓ GroupBy aggregation test passed');
}

function testGroupByWithNulls() {
  console.log('Testing: GroupBy with Null Values');
  const csv = `name,category
John,A
Jane,null
Bob,A
Alice,null
Charlie,B`;

  const result = parseCSV(csv);

  const grouped = result.groupBy('category');
  assertEquals(grouped.size, 3, 'Should have 3 groups (A, null, B)');
  assertEquals(grouped.get('A')?.length, 2, 'Category A should have 2 rows');
  assertEquals(grouped.get(null)?.length, 2, 'Null category should have 2 rows');
  assertEquals(grouped.get('B')?.length, 1, 'Category B should have 1 row');
  console.log('✓ GroupBy with nulls test passed');
}

function testEmptyInput() {
  console.log('Testing: Empty Input');
  const result1 = parseCSV('');
  assertEquals(result1.rows.length, 0, 'Empty string should return no rows');
  assertEquals(result1.headers.length, 0, 'Empty string should return no headers');
  assertEquals(result1.count(), 0, 'Count of empty input should be 0');

  const result2 = parseCSV('   \n  \n  ');
  assertEquals(result2.rows.length, 0, 'Whitespace-only input should return no rows');
  console.log('✓ Empty input test passed');
}

function testSingleColumn() {
  console.log('Testing: Single Column');
  const csv = `name
John
Jane
Bob`;

  const result = parseCSV(csv);

  assertEquals(result.headers.length, 1, 'Should have 1 header');
  assertEquals(result.count(), 3, 'Should have 3 rows');
  assertEquals(result.rows[0].name, 'John', 'Single column should work');
  console.log('✓ Single column test passed');
}

function testSingleRow() {
  console.log('Testing: Single Row');
  const csv = `name,age,city
John,25,New York`;

  const result = parseCSV(csv);

  assertEquals(result.count(), 1, 'Should have 1 row');
  assertEquals(result.rows[0].name, 'John', 'Single row should work');
  console.log('✓ Single row test passed');
}

function testVeryLargeField() {
  console.log('Testing: Very Large Field');
  const largeValue = 'x'.repeat(10000);
  const csv = `name,description
John,"${largeValue}"
Jane,Short`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0].description.length, 10000, 'Large field should be parsed correctly');
  assertEquals(result.rows[0].description, largeValue, 'Large field value should match');
  console.log('✓ Very large field test passed');
}

function testMultilineFields() {
  console.log('Testing: Multiline Fields');
  const csv = `name,description,age
John,"Line 1
Line 2
Line 3",25
Jane,"Another
Multiline",30`;

  const result = parseCSV(csv);

  assertEquals(result.count(), 2, 'Should have 2 rows despite multiline fields');
  assert(result.rows[0].description.includes('\n'), 'Multiline field should contain newline');
  assertEquals(result.rows[0].age, 25, 'Age should still be coerced correctly');
  console.log('✓ Multiline fields test passed');
}

function testQuotedEmptyField() {
  console.log('Testing: Quoted Empty Field');
  const csv = `name,middle,last
John,"",Doe
Jane,"",Smith`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0].middle, null, 'Empty quoted field should be null');
  assertEquals(result.rows[1].middle, null, 'Another empty quoted field should be null');
  console.log('✓ Quoted empty field test passed');
}

function testComplexExample() {
  console.log('Testing: Complex Real-world Example');
  const csv = `product_id,name,description,price,quantity,is_active,category,notes
1,"Product ""A""","High quality item, great value",99.99,100,true,"Electronics","In stock"
2,"Product B","Basic model, budget friendly",49.50,50,true,"Electronics",null
3,"Product ""C""","Discontinued item, no longer available",0,0,false,"Archived","Moved to storage"`;

  const result = parseCSV(csv);

  assertEquals(result.count(), 3, 'Should have 3 rows');
  assertEquals(result.rows[0].name, 'Product "A"', 'Escaped quotes should work');
  assertEquals(result.rows[0].price, 99.99, 'Float prices should be coerced');
  assertEquals(result.rows[0].is_active, true, 'Boolean should be coerced');
  assertEquals(result.rows[2].quantity, 0, 'Zero should be coerced to number');
  assertEquals(result.rows[1].notes, null, 'Null value should be null');

  const activeProducts = result.filter(row => row.is_active === true);
  assertEquals(activeProducts.length, 2, 'Should filter to 2 active products');

  const electronicsSum = activeProducts
    .filter(row => row.category === 'Electronics')
    .reduce((sum, row) => sum + (row.price * row.quantity), 0);
  assertEquals(electronicsSum, 12497.5, 'Complex calculation should work');

  console.log('✓ Complex real-world example test passed');
}

function testUnclosedQuoteError() {
  console.log('Testing: Unclosed Quote Error Handling');
  const csv = `name,description
John,"Unclosed quote here
Jane,OK`;

  const result = parseCSV(csv);

  assert(result.errors.length > 0, 'Should have error for unclosed quote');
  assert(result.errors[0].message.includes('Unclosed'), 'Error message should mention unclosed quote');
  console.log('✓ Unclosed quote error handling test passed');
}

// Run all tests
console.log('\n========== Running CSV Parser Tests ==========\n');

const tests = [
  testBasicParsing,
  testQuotedFields,
  testEscapedQuotes,
  testCustomDelimiters,
  testCustomQuoteChar,
  testCustomLineSeparator,
  testTypeCoercionNumbers,
  testTypeCoercionBooleans,
  testTypeCoercionNulls,
  testTypeCoercionStrings,
  testNegativeNumbers,
  testMalformedRows,
  testFilterFunctionality,
  testSumAggregation,
  testAverageAggregation,
  testAverageWithNulls,
  testCountAggregation,
  testGroupByAggregation,
  testGroupByWithNulls,
  testEmptyInput,
  testSingleColumn,
  testSingleRow,
  testVeryLargeField,
  testMultilineFields,
  testQuotedEmptyField,
  testComplexExample,
  testUnclosedQuoteError
];

let passed = 0;
let failed = 0;

for (const test of tests) {
  try {
    test();
    passed++;
  } catch (error) {
    console.error(`✗ ${test.name} failed:`, error instanceof Error ? error.message : error);
    failed++;
  }
  console.log('');
}

console.log('========== Test Results ==========');
console.log(`Total: ${passed + failed}`);
console.log(`Passed: ${passed}`);
console.log(`Failed: ${failed}`);

if (failed > 0) {
  process.exit(1);
}

function coerceType(value) {
  // Handle null cases
  if (value === '' || value === 'null' || value === 'NULL') {
    return null;
  }

  // Handle booleans (case insensitive)
  if (value.toLowerCase() === 'true') {
    return true;
  }
  if (value.toLowerCase() === 'false') {
    return false;
  }

  // Handle numbers (int and float)
  if (/^-?\d+$/.test(value)) {
    return parseInt(value, 10);
  }
  if (/^-?\d*\.\d+$/.test(value)) {
    return parseFloat(value);
  }

  // Everything else is a string
  return value;
}

function parseCSVContent(
  input,
  delimiter = ',',
  quoteChar = '"',
  lineSeparator = '\n'
) {
  const errors = [];
  const rows = [];

  // Split by line separator
  const lines = input.split(lineSeparator);

  let currentRow = [];
  let currentField = '';
  let insideQuotes = false;
  let lineNumber = 0;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];

    for (let j = 0; j < line.length; j++) {
      const char = line[j];
      const nextChar = j + 1 < line.length ? line[j + 1] : null;

      if (char === quoteChar) {
        if (nextChar === quoteChar) {
          // Escaped quote - add one quote and skip next
          currentField += quoteChar;
          j++;
        } else {
          // Toggle quote state
          insideQuotes = !insideQuotes;
        }
      } else if (char === delimiter && !insideQuotes) {
        // Field separator
        currentRow.push(currentField);
        currentField = '';
      } else {
        currentField += char;
      }
    }

    // Handle end of line
    if (insideQuotes && i < lines.length - 1) {
      // Still inside quotes, add the line separator back
      currentField += lineSeparator;
    } else {
      // End of row
      if (currentField || currentRow.length > 0) {
        currentRow.push(currentField);
      }

      if (currentRow.length > 0) {
        // Check for unclosed quotes
        if (insideQuotes) {
          errors.push({
            row: lineNumber,
            message: 'Unclosed quote in row'
          });
        }
        rows.push(currentRow);
        currentRow = [];
        currentField = '';
      }

      lineNumber++;
    }
  }

  // Handle any remaining field/row at end of input
  if (currentField || currentRow.length > 0) {
    if (insideQuotes) {
      errors.push({
        row: lineNumber,
        message: 'Unclosed quote at end of input'
      });
    }
    currentRow.push(currentField);
    if (currentRow.length > 0) {
      rows.push(currentRow);
    }
  }

  return { rows, errors };
}

function parseCSV(input, options = {}) {
  const delimiter = options.delimiter ?? ',';
  const quoteChar = options.quoteChar ?? '"';
  const lineSeparator = options.lineSeparator ?? '\n';

  if (!input || input.trim() === '') {
    return {
      rows: [],
      headers: [],
      errors: [],
      filter: () => [],
      sum: () => 0,
      average: () => 0,
      count: () => 0,
      groupBy: () => new Map()
    };
  }

  const { rows: rawRows, errors: parseErrors } = parseCSVContent(
    input,
    delimiter,
    quoteChar,
    lineSeparator
  );

  if (rawRows.length === 0) {
    return {
      rows: [],
      headers: [],
      errors: parseErrors,
      filter: () => [],
      sum: () => 0,
      average: () => 0,
      count: () => 0,
      groupBy: () => new Map()
    };
  }

  const headers = rawRows[0];
  const rows = [];
  const errors = [...parseErrors];

  // Parse data rows
  for (let i = 1; i < rawRows.length; i++) {
    const rawRow = rawRows[i];

    // Check if row has correct number of fields
    if (rawRow.length !== headers.length) {
      errors.push({
        row: i,
        message: `Expected ${headers.length} fields, got ${rawRow.length}`
      });
    }

    const row = {};
    for (let j = 0; j < headers.length; j++) {
      const header = headers[j];
      const value = rawRow[j] ?? '';
      row[header] = coerceType(value);
    }
    rows.push(row);
  }

  // Helper methods
  const filter = (predicate) => {
    return rows.filter(predicate);
  };

  const sum = (column) => {
    return rows.reduce((acc, row) => {
      const value = row[column];
      if (typeof value === 'number') {
        return acc + value;
      }
      return acc;
    }, 0);
  };

  const average = (column) => {
    const numericRows = rows.filter(row => typeof row[column] === 'number');
    if (numericRows.length === 0) return 0;
    return sum(column) / numericRows.length;
  };

  const count = () => {
    return rows.length;
  };

  const groupBy = (column) => {
    const map = new Map();
    for (const row of rows) {
      const key = row[column];
      if (!map.has(key)) {
        map.set(key, []);
      }
      map.get(key).push(row);
    }
    return map;
  };

  return {
    rows,
    headers,
    errors,
    filter,
    sum,
    average,
    count,
    groupBy
  };
}

// Export for Node.js
if (typeof module !== 'undefined' && module.exports) {
  module.exports = { parseCSV };
}

const { parseCSV } = require('./csv-parser.js');

function assert(condition, message) {
  if (!condition) {
    throw new Error(`Assertion failed: ${message}`);
  }
}

function assertEquals(actual, expected, message) {
  if (JSON.stringify(actual) !== JSON.stringify(expected)) {
    throw new Error(`Assertion failed: ${message}\nExpected: ${JSON.stringify(expected)}\nActual: ${JSON.stringify(actual)}`);
  }
}

function testBasicParsing() {
  console.log('Testing: Basic Parsing');
  const csv = `name,age,city
John,25,New York
Jane,30,Los Angeles
Bob,35,Chicago`;

  const result = parseCSV(csv);

  assertEquals(result.headers, ['name', 'age', 'city'], 'Headers should be correct');
  assertEquals(result.count(), 3, 'Should have 3 rows');
  assertEquals(result.rows[0].name, 'John', 'First row name should be John');
  assertEquals(result.rows[0].age, 25, 'First row age should be 25 (coerced to number)');
  assertEquals(result.errors.length, 0, 'Should have no parsing errors');
  console.log('✓ Basic parsing test passed');
}

function testQuotedFields() {
  console.log('Testing: Quoted Fields with Commas');
  const csv = `name,description,price
"John Doe","A person, very nice",100
"Jane Smith","Another person, also nice",200`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0].name, 'John Doe', 'Quoted name should work');
  assertEquals(result.rows[0].description, 'A person, very nice', 'Quoted field with comma should work');
  assertEquals(result.rows[0].price, 100, 'Price should be coerced to number');
  assertEquals(result.errors.length, 0, 'Should have no parsing errors');
  console.log('✓ Quoted fields test passed');
}

function testEscapedQuotes() {
  console.log('Testing: Escaped Quotes');
  const csv = `name,comment
"John ""The Man"" Doe","He said ""Hello"""
"Jane ""The Woman"" Smith","She replied ""Hi"""`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0].name, 'John "The Man" Doe', 'Double quotes should be escaped');
  assertEquals(result.rows[0].comment, 'He said "Hello"', 'Escaped quotes in value should work');
  assertEquals(result.rows[1].name, 'Jane "The Woman" Smith', 'Another escaped quote test');
  assertEquals(result.errors.length, 0, 'Should have no parsing errors');
  console.log('✓ Escaped quotes test passed');
}

function testCustomDelimiters() {
  console.log('Testing: Custom Delimiters');
  const csv = `name;age;city
John;25;New York
Jane;30;Los Angeles`;

  const result = parseCSV(csv, { delimiter: ';' });

  assertEquals(result.headers, ['name', 'age', 'city'], 'Should parse with semicolon delimiter');
  assertEquals(result.rows[0].name, 'John', 'First field should be correct');
  assertEquals(result.rows[0].age, 25, 'Second field should be correct');
  assertEquals(result.errors.length, 0, 'Should have no parsing errors');
  console.log('✓ Custom delimiters test passed');
}

function testCustomQuoteChar() {
  console.log('Testing: Custom Quote Character');
  const csv = `name,description,price
'John Doe','A person, very nice',100
'Jane Smith','Another person, also nice',200`;

  const result = parseCSV(csv, { quoteChar: "'" });

  assertEquals(result.rows[0].name, 'John Doe', 'Single quote should work as quote char');
  assertEquals(result.rows[0].description, 'A person, very nice', 'Field with comma should work with single quotes');
  assertEquals(result.errors.length, 0, 'Should have no parsing errors');
  console.log('✓ Custom quote character test passed');
}

function testCustomLineSeparator() {
  console.log('Testing: Custom Line Separator');
  const csv = `name,age,city\rJohn,25,New York\rJane,30,Los Angeles`;

  const result = parseCSV(csv, { lineSeparator: '\r' });

  assertEquals(result.headers, ['name', 'age', 'city'], 'Should parse with custom line separator');
  assertEquals(result.count(), 2, 'Should have 2 rows');
  assertEquals(result.errors.length, 0, 'Should have no parsing errors');
  console.log('✓ Custom line separator test passed');
}

function testTypeCoercionNumbers() {
  console.log('Testing: Type Coercion - Numbers');
  const csv = `name,intValue,floatValue
John,42,3.14
Jane,100,2.71828`;

  const result = parseCSV(csv);

  assertEquals(typeof result.rows[0].intValue, 'number', 'Integer should be coerced to number');
  assertEquals(result.rows[0].intValue, 42, 'Integer value should be correct');
  assertEquals(typeof result.rows[0].floatValue, 'number', 'Float should be coerced to number');
  assertEquals(result.rows[0].floatValue, 3.14, 'Float value should be correct');
  assertEquals(result.rows[1].intValue, 100, 'Another integer should work');
  console.log('✓ Type coercion - numbers test passed');
}

function testTypeCoercionBooleans() {
  console.log('Testing: Type Coercion - Booleans');
  const csv = `name,isActive,isVip
John,true,False
Jane,TRUE,FALSE
Bob,false,true`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0].isActive, true, 'true should be coerced to boolean');
  assertEquals(result.rows[0].isVip, false, 'False should be coerced to boolean (case insensitive)');
  assertEquals(result.rows[1].isActive, true, 'TRUE should be coerced to boolean');
  assertEquals(result.rows[2].isActive, false, 'false should be coerced to boolean');
  console.log('✓ Type coercion - booleans test passed');
}

function testTypeCoercionNulls() {
  console.log('Testing: Type Coercion - Nulls');
  const csv = `name,nullValue,NULLValue,emptyValue
John,null,NULL,
Jane,NULL,null,`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0].nullValue, null, 'null should be coerced to null');
  assertEquals(result.rows[0].NULLValue, null, 'NULL should be coerced to null');
  assertEquals(result.rows[0].emptyValue, null, 'Empty string should be coerced to null');
  assertEquals(result.rows[1].nullValue, null, 'NULL should be coerced to null');
  console.log('✓ Type coercion - nulls test passed');
}

function testTypeCoercionStrings() {
  console.log('Testing: Type Coercion - Strings');
  const csv = `name,value
John,hello
Jane,world123
Bob,3.14x`;

  const result = parseCSV(csv);

  assertEquals(typeof result.rows[0].value, 'string', 'Non-numeric value should stay string');
  assertEquals(result.rows[0].value, 'hello', 'String value should be correct');
  assertEquals(result.rows[1].value, 'world123', 'Mixed alphanumeric should stay string');
  assertEquals(result.rows[2].value, '3.14x', 'Invalid number should stay string');
  console.log('✓ Type coercion - strings test passed');
}

function testNegativeNumbers() {
  console.log('Testing: Negative Numbers');
  const csv = `name,intValue,floatValue
John,-42,-3.14
Jane,-100,-2.71828`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0].intValue, -42, 'Negative integer should work');
  assertEquals(result.rows[0].floatValue, -3.14, 'Negative float should work');
  console.log('✓ Negative numbers test passed');
}

function testMalformedRows() {
  console.log('Testing: Malformed Row Error Collection');
  const csv = `name,age,city
John,25,New York
Jane,30
Bob,35,Chicago,Extra`;

  const result = parseCSV(csv);

  assertEquals(result.count(), 3, 'Should still parse all rows despite errors');
  assertEquals(result.errors.length, 2, 'Should have 2 errors for malformed rows');
  assert(result.errors[0].row === 2, 'First error should be on row 2');
  assert(result.errors[1].row === 4, 'Second error should be on row 4');
  assert(result.errors[0].message.includes('Expected 3 fields'), 'Error message should indicate field mismatch');
  console.log('✓ Malformed rows test passed');
}

function testFilterFunctionality() {
  console.log('Testing: Filter Functionality');
  const csv = `name,age,city
John,25,New York
Jane,30,Los Angeles
Bob,35,Chicago
Alice,22,New York`;

  const result = parseCSV(csv);

  const filtered = result.filter((row) => row.age > 25);
  assertEquals(filtered.length, 3, 'Filter should return 3 rows with age > 25');
  assert(filtered.every(row => row.age > 25), 'All filtered rows should have age > 25');

  const byCity = result.filter((row) => row.city === 'New York');
  assertEquals(byCity.length, 2, 'Filter should return 2 rows from New York');
  console.log('✓ Filter functionality test passed');
}

function testSumAggregation() {
  console.log('Testing: Sum Aggregation');
  const csv = `name,salary
John,50000
Jane,60000
Bob,55000
Alice,65000`;

  const result = parseCSV(csv);

  const total = result.sum('salary');
  assertEquals(total, 230000, 'Sum should be correct');

  const filtered = result.filter((row) => row.name !== 'Alice');
  // Note: filter returns array, not CSVResult, so we need to manually sum
  const filterSum = filtered.reduce((sum, row) => sum + row.salary, 0);
  assertEquals(filterSum, 165000, 'Sum on filtered rows should be correct');
  console.log('✓ Sum aggregation test passed');
}

function testAverageAggregation() {
  console.log('Testing: Average Aggregation');
  const csv = `name,score
John,85
Jane,90
Bob,75
Alice,95`;

  const result = parseCSV(csv);

  const avg = result.average('score');
  assertEquals(avg, 86.25, 'Average should be correct');
  console.log('✓ Average aggregation test passed');
}

function testAverageWithNulls() {
  console.log('Testing: Average with Null Values');
  const csv = `name,score
John,85
Jane,null
Bob,75
Alice,95`;

  const result = parseCSV(csv);

  const avg = result.average('score');
  assertEquals(avg, 85, 'Average should ignore null values and calculate from 3 numbers');
  console.log('✓ Average with nulls test passed');
}

function testCountAggregation() {
  console.log('Testing: Count Aggregation');
  const csv = `name,age
John,25
Jane,30
Bob,35`;

  const result = parseCSV(csv);

  const count = result.count();
  assertEquals(count, 3, 'Count should return 3');
  console.log('✓ Count aggregation test passed');
}

function testGroupByAggregation() {
  console.log('Testing: GroupBy Aggregation');
  const csv = `name,department,salary
John,Sales,50000
Jane,Engineering,60000
Bob,Sales,55000
Alice,Engineering,65000`;

  const result = parseCSV(csv);

  const grouped = result.groupBy('department');
  assertEquals(grouped.size, 2, 'Should have 2 groups');
  assertEquals(grouped.get('Sales')?.length, 2, 'Sales group should have 2 rows');
  assertEquals(grouped.get('Engineering')?.length, 2, 'Engineering group should have 2 rows');

  const salesGroup = grouped.get('Sales');
  assert(salesGroup?.every(row => row.department === 'Sales'), 'All rows in group should have matching value');
  console.log('✓ GroupBy aggregation test passed');
}

function testGroupByWithNulls() {
  console.log('Testing: GroupBy with Null Values');
  const csv = `name,category
John,A
Jane,null
Bob,A
Alice,null
Charlie,B`;

  const result = parseCSV(csv);

  const grouped = result.groupBy('category');
  assertEquals(grouped.size, 3, 'Should have 3 groups (A, null, B)');
  assertEquals(grouped.get('A')?.length, 2, 'Category A should have 2 rows');
  assertEquals(grouped.get(null)?.length, 2, 'Null category should have 2 rows');
  assertEquals(grouped.get('B')?.length, 1, 'Category B should have 1 row');
  console.log('✓ GroupBy with nulls test passed');
}

function testEmptyInput() {
  console.log('Testing: Empty Input');
  const result1 = parseCSV('');
  assertEquals(result1.rows.length, 0, 'Empty string should return no rows');
  assertEquals(result1.headers.length, 0, 'Empty string should return no headers');
  assertEquals(result1.count(), 0, 'Count of empty input should be 0');

  const result2 = parseCSV('   \n  \n  ');
  assertEquals(result2.rows.length, 0, 'Whitespace-only input should return no rows');
  console.log('✓ Empty input test passed');
}

function testSingleColumn() {
  console.log('Testing: Single Column');
  const csv = `name
John
Jane
Bob`;

  const result = parseCSV(csv);

  assertEquals(result.headers.length, 1, 'Should have 1 header');
  assertEquals(result.count(), 3, 'Should have 3 rows');
  assertEquals(result.rows[0].name, 'John', 'Single column should work');
  console.log('✓ Single column test passed');
}

function testSingleRow() {
  console.log('Testing: Single Row');
  const csv = `name,age,city
John,25,New York`;

  const result = parseCSV(csv);

  assertEquals(result.count(), 1, 'Should have 1 row');
  assertEquals(result.rows[0].name, 'John', 'Single row should work');
  console.log('✓ Single row test passed');
}

function testVeryLargeField() {
  console.log('Testing: Very Large Field');
  const largeValue = 'x'.repeat(10000);
  const csv = `name,description
John,"${largeValue}"
Jane,Short`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0].description.length, 10000, 'Large field should be parsed correctly');
  assertEquals(result.rows[0].description, largeValue, 'Large field value should match');
  console.log('✓ Very large field test passed');
}

function testMultilineFields() {
  console.log('Testing: Multiline Fields');
  const csv = `name,description,age
John,"Line 1
