  const result = parseCSV(csv);

  assertEquals(result.count(), 2, 'Should have 2 rows despite multiline fields');
  assert(result.rows[0].description.includes('\n'), 'Multiline field should contain newline');
  assertEquals(result.rows[0].age, 25, 'Age should still be coerced correctly');
  console.log('✓ Multiline fields test passed');
}

function testQuotedEmptyField() {
  console.log('Testing: Quoted Empty Field');
  const csv = `name,middle,last
John,"",Doe
Jane,"",Smith`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0].middle, null, 'Empty quoted field should be null');
  assertEquals(result.rows[1].middle, null, 'Another empty quoted field should be null');
  console.log('✓ Quoted empty field test passed');
}

function testComplexExample() {
  console.log('Testing: Complex Real-world Example');
  const csv = `product_id,name,description,price,quantity,is_active,category,notes
1,"Product ""A""","High quality item, great value",99.99,100,true,"Electronics","In stock"
2,"Product B","Basic model, budget friendly",49.50,50,true,"Electronics",null
3,"Product ""C""","Discontinued item, no longer available",0,0,false,"Archived","Moved to storage"`;

  const result = parseCSV(csv);

  assertEquals(result.count(), 3, 'Should have 3 rows');
  assertEquals(result.rows[0].name, 'Product "A"', 'Escaped quotes should work');
  assertEquals(result.rows[0].price, 99.99, 'Float prices should be coerced');
  assertEquals(result.rows[0].is_active, true, 'Boolean should be coerced');
  assertEquals(result.rows[2].quantity, 0, 'Zero should be coerced to number');
  assertEquals(result.rows[1].notes, null, 'Null value should be null');

  const activeProducts = result.filter(row => row.is_active === true);
  assertEquals(activeProducts.length, 2, 'Should filter to 2 active products');

  const electronicsSum = activeProducts
    .filter(row => row.category === 'Electronics')
    .reduce((sum, row) => sum + (row.price * row.quantity), 0);
  assertEquals(electronicsSum, 12497.5, 'Complex calculation should work');

  console.log('✓ Complex real-world example test passed');
}

function testUnclosedQuoteError() {
  console.log('Testing: Unclosed Quote Error Handling');
  const csv = `name,description
John,"Unclosed quote here
Jane,OK`;

  const result = parseCSV(csv);

  assert(result.errors.length > 0, 'Should have error for unclosed quote');
  assert(result.errors[0].message.includes('Unclosed'), 'Error message should mention unclosed quote');
  console.log('✓ Unclosed quote error handling test passed');
}

// Run all tests
console.log('\n========== Running CSV Parser Tests ==========\n');

const tests = [
  testBasicParsing,
  testQuotedFields,
  testEscapedQuotes,
  testCustomDelimiters,
  testCustomQuoteChar,
  testCustomLineSeparator,
  testTypeCoercionNumbers,
  testTypeCoercionBooleans,
  testTypeCoercionNulls,
  testTypeCoercionStrings,
  testNegativeNumbers,
  testMalformedRows,
  testFilterFunctionality,
  testSumAggregation,
  testAverageAggregation,
  testAverageWithNulls,
  testCountAggregation,
  testGroupByAggregation,
  testGroupByWithNulls,
  testEmptyInput,
  testSingleColumn,
  testSingleRow,
  testVeryLargeField,
  testMultilineFields,
  testQuotedEmptyField,
  testComplexExample,
  testUnclosedQuoteError
];

let passed = 0;
let failed = 0;

for (const test of tests) {
  try {
    test();
    passed++;
  } catch (error) {
    console.error(`✗ ${test.name} failed:`, error instanceof Error ? error.message : error);
    failed++;
  }
  console.log('');
}

console.log('========== Test Results ==========');
console.log(`Total: ${passed + failed}`);
console.log(`Passed: ${passed}`);
console.log(`Failed: ${failed}`);

if (failed > 0) {
  process.exit(1);
}

