import { parseCSV } from './csv-parser';

// ============================================
// Example 1: Basic Parsing
// ============================================
console.log('Example 1: Basic Parsing\n');

const basicCSV = `name,age,city
John,25,New York
Jane,30,Los Angeles
Bob,35,Chicago`;

const basicResult = parseCSV(basicCSV);
console.log('Headers:', basicResult.headers);
console.log('Row count:', basicResult.count());
console.log('First row:', basicResult.rows[0]);
console.log();

// ============================================
// Example 2: Quoted Fields with Special Characters
// ============================================
console.log('Example 2: Quoted Fields\n');

const quotedCSV = `product,description,price
"Laptop Pro","High-performance, great value",1299.99
"USB Cable","3ft, black color",9.99
"Monitor Stand","Adjustable, steel frame",79.50`;

const quotedResult = parseCSV(quotedCSV);
console.log('Products:');
quotedResult.rows.forEach(row => {
  console.log(`  ${row.product}: ${row.description} - $${row.price}`);
});
console.log();

// ============================================
// Example 3: Escaped Quotes in Data
// ============================================
console.log('Example 3: Escaped Quotes\n');

const escapedCSV = `name,quote
"John ""The King"" Doe","He said ""I am the king"""
"Jane ""The Queen"" Smith","She replied ""Not yet"""`;

const escapedResult = parseCSV(escapedCSV);
escapedResult.rows.forEach(row => {
  console.log(`${row.name}: ${row.quote}`);
});
console.log();

// ============================================
// Example 4: Type Coercion
// ============================================
console.log('Example 4: Type Coercion\n');

const typesCSV = `name,salary,is_manager,department,notes
John,75000,true,Engineering,"Top performer"
Jane,65000,false,Sales,null
Bob,0,null,null,Inactive`;

const typesResult = parseCSV(typesCSV);
console.log('Employee data with types:');
typesResult.rows.forEach(row => {
