  console.log('Testing: Escaped Quotes');
  const csv = `name,comment
"John ""The Man"" Doe","He said ""Hello"""
"Jane ""The Woman"" Smith","She replied ""Hi"""`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0].name, 'John "The Man" Doe', 'Double quotes should be escaped');
  assertEquals(result.rows[0].comment, 'He said "Hello"', 'Escaped quotes in value should work');
  assertEquals(result.rows[1].name, 'Jane "The Woman" Smith', 'Another escaped quote test');
  assertEquals(result.errors.length, 0, 'Should have no parsing errors');
  console.log('✓ Escaped quotes test passed');
}

