/**
 * CSV Parser Examples
 * 
 * Quick reference examples of common CSV parsing tasks
 */

import { parseCSV } from './csv-parser';

// ============================================
// Example 1: Basic Parsing
// ============================================
console.log('Example 1: Basic Parsing\n');

const basicCSV = `name,age,city
John,25,New York
Jane,30,Los Angeles
Bob,35,Chicago`;

const basicResult = parseCSV(basicCSV);
console.log('Headers:', basicResult.headers);
console.log('Row count:', basicResult.count());
console.log('First row:', basicResult.rows[0]);
console.log();

// ============================================
// Example 2: Quoted Fields with Special Characters
// ============================================
console.log('Example 2: Quoted Fields\n');

const quotedCSV = `product,description,price
"Laptop Pro","High-performance, great value",1299.99
"USB Cable","3ft, black color",9.99
"Monitor Stand","Adjustable, steel frame",79.50`;

const quotedResult = parseCSV(quotedCSV);
console.log('Products:');
quotedResult.rows.forEach(row => {
  console.log(`  ${row.product}: ${row.description} - $${row.price}`);
});
console.log();

// ============================================
// Example 3: Escaped Quotes in Data
// ============================================
console.log('Example 3: Escaped Quotes\n');

const escapedCSV = `name,quote
"John ""The King"" Doe","He said ""I am the king"""
"Jane ""The Queen"" Smith","She replied ""Not yet"""`;

const escapedResult = parseCSV(escapedCSV);
escapedResult.rows.forEach(row => {
  console.log(`${row.name}: ${row.quote}`);
});
console.log();

// ============================================
// Example 4: Type Coercion
// ============================================
console.log('Example 4: Type Coercion\n');

const typesCSV = `name,salary,is_manager,department,notes
John,75000,true,Engineering,"Top performer"
Jane,65000,false,Sales,null
Bob,0,null,null,Inactive`;

const typesResult = parseCSV(typesCSV);
console.log('Employee data with types:');
typesResult.rows.forEach(row => {
  console.log(`  ${row.name}:`);
  console.log(`    salary: ${row.salary} (${typeof row.salary})`);
  console.log(`    is_manager: ${row.is_manager} (${typeof row.is_manager})`);
  console.log(`    notes: ${row.notes}`);
});
console.log();

// ============================================
// Example 5: Filtering Data
// ============================================
console.log('Example 5: Filtering Data\n');

const employeesCSV = `name,age,salary,department
John,28,75000,Engineering
Jane,35,85000,Engineering
Bob,42,65000,Sales
Alice,26,60000,Sales
Charlie,38,70000,HR`;

const employeesResult = parseCSV(employeesCSV);

// Filter engineers
const engineers = employeesResult.filter(row => row.department === 'Engineering');
console.log('Engineers:', engineers.map(e => e.name).join(', '));

// Filter high earners
const highEarners = employeesResult.filter(row => row.salary > 70000);
console.log('High earners (>$70k):', highEarners.map(e => `${e.name} ($${e.salary})`).join(', '));
console.log();

// ============================================
// Example 6: Aggregations
// ============================================
console.log('Example 6: Aggregations\n');

const salesCSV = `product,region,revenue,units_sold
Widget,North,50000,1000
Widget,South,45000,900
Gadget,North,75000,500
Gadget,South,80000,550
Tool,North,30000,600
Tool,South,35000,700`;

const salesResult = parseCSV(salesCSV);

console.log(`Total revenue: $${salesResult.sum('revenue').toLocaleString()}`);
console.log(`Average revenue per product: $${salesResult.average('revenue').toFixed(2)}`);
console.log(`Total products: ${salesResult.count()}`);
console.log();

// ============================================
// Example 7: GroupBy - Group by Region
// ============================================
console.log('Example 7: GroupBy - Group by Region\n');

const byRegion = salesResult.groupBy('region');
byRegion.forEach((rows, region) => {
  const total = rows.reduce((sum, row) => sum + row.revenue, 0);
  console.log(`${region}: $${total.toLocaleString()} (${rows.length} products)`);
});
console.log();

// ============================================
// Example 8: GroupBy - Group by Product
// ============================================
console.log('Example 8: GroupBy - Group by Product\n');

const byProduct = salesResult.groupBy('product');
byProduct.forEach((rows, product) => {
  const total = rows.reduce((sum, row) => sum + row.revenue, 0);
  const totalUnits = rows.reduce((sum, row) => sum + row.units_sold, 0);
  console.log(`${product}: $${total.toLocaleString()} revenue, ${totalUnits} units sold`);
});
console.log();

// ============================================
// Example 9: Custom Delimiters
// ============================================
console.log('Example 9: Custom Delimiters\n');

const tabDelimitedCSV = `name\tage\tcity
John\t25\tNew York
Jane\t30\tBoston`;

const tabResult = parseCSV(tabDelimitedCSV, { delimiter: '\t' });
console.log('Tab-delimited CSV:');
console.log('Headers:', tabResult.headers);
console.log('First row:', tabResult.rows[0]);
console.log();

// ============================================
// Example 10: Error Handling
// ============================================
console.log('Example 10: Error Handling\n');

const errorCSV = `name,age,city
John,25,New York
Jane,30
Bob,35,Chicago,Extra,Fields`;

const errorResult = parseCSV(errorCSV);
console.log(`Parsed ${errorResult.count()} rows`);
console.log(`Found ${errorResult.errors.length} parsing errors:`);
errorResult.errors.forEach(err => {
  console.log(`  Row ${err.row}: ${err.message}`);
});
console.log();

// ============================================
// Example 11: Multiline Fields
// ============================================
console.log('Example 11: Multiline Fields\n');

const multilineCSV = `product,description,price
"Product A","This is a multi-line
description that spans
multiple lines",99.99
"Product B","Single line description",49.99`;

const multilineResult = parseCSV(multilineCSV);
multilineResult.rows.forEach(row => {
  console.log(`${row.product}:`);
  console.log(`  ${row.description.replace(/\n/g, '\n  ')}`);
  console.log(`  Price: $${row.price}`);
  console.log();
});

// ============================================
// Example 12: Complex Real-World Example
// ============================================
console.log('Example 12: Complex Real-World Scenario\n');

const analyticsCSV = `date,campaign,impressions,clicks,conversions,revenue
2024-01-01,"Campaign A",10000,250,45,1350
2024-01-01,"Campaign B",8000,150,20,600
2024-01-02,"Campaign A",12000,300,60,1800
2024-01-02,"Campaign B",9000,180,25,750
2024-01-03,"Campaign A",11000,275,50,1500
2024-01-03,"Campaign B",8500,160,22,660`;

const analyticsResult = parseCSV(analyticsCSV);

// Group by campaign
const byCampaign = analyticsResult.groupBy('campaign');

console.log('Campaign Performance Summary:\n');
byCampaign.forEach((rows, campaign) => {
  const totalImpressions = rows.reduce((sum, r) => sum + r.impressions, 0);
  const totalClicks = rows.reduce((sum, r) => sum + r.clicks, 0);
  const totalConversions = rows.reduce((sum, r) => sum + r.conversions, 0);
  const totalRevenue = rows.reduce((sum, r) => sum + r.revenue, 0);

  const ctr = ((totalClicks / totalImpressions) * 100).toFixed(2);
  const conversionRate = ((totalConversions / totalClicks) * 100).toFixed(2);
  const aov = (totalRevenue / totalConversions).toFixed(2);

  console.log(`${campaign}:`);
  console.log(`  Impressions: ${totalImpressions.toLocaleString()}`);
  console.log(`  Clicks: ${totalClicks} (CTR: ${ctr}%)`);
  console.log(`  Conversions: ${totalConversions} (${conversionRate}% conversion rate)`);
  console.log(`  Revenue: $${totalRevenue.toLocaleString()}`);
  console.log(`  AOV: $${aov}\n`);
});
